'use strict';

const itemBanks = require('./item_content.cjs');
const S = itemBanks.sources;

const chapter = (id, skillId, title, summary, objectives, sections, flashcards) => ({ id, skillId, title, summary, objectives, sections, flashcards });
const section = (heading, content, keyTerms) => ({ heading, content, keyTerms });

const chapters = [
  chapter('sp5355-ch-01', 'development-milestones-context', 'Development, Context, and Learner Variability',
    'Use developmental knowledge without turning milestones, culture, language, or one observation into a diagnosis; describe strengths and needs across authentic contexts.',
    ['Interpret broad developmental patterns with appropriate caution.', 'Separate observed performance from labels and assumptions.', 'Analyze how task and environment interact with learner characteristics.'], [
      section('Milestones are reference points, not verdicts', 'Development includes linguistic, cognitive, physical, adaptive, and social-emotional dimensions. Milestones describe broad patterns and help educators notice when more information may be useful, but an average is not a diagnostic cutoff. Compare repeated observations across time and settings, consider opportunity and access, and consult qualified team members. A single late-emerging skill, especially during illness, transition, or language acquisition, cannot establish a disability. Planning begins with what the learner can do, the conditions that support success, and the next meaningful skill.', ['developmental milestone', 'learner variability', 'multiple sources']),
      section('The learner-task-environment interaction', 'Performance changes when task demands, sensory conditions, language load, familiarity, adult prompts, peer arrangements, or motivation change. Instead of treating variable performance as inconsistency or defiance, compare the conditions systematically. Ask what the task requires, what the learner already knows, which access barriers are present, and what happens when one support changes. This ecological analysis often identifies an instructional or environmental adjustment that is more useful than a global trait statement.', ['ecological perspective', 'task demand', 'access barrier']),
      section('Culture, language, and opportunity to learn', 'Cultural and linguistic difference is not disability. Teams need evidence about language exposure, instruction, attendance, mobility, prior schooling, performance in the home language, and response to appropriate support. Assessment and instruction should use communication modes and examples that allow the learner to show knowledge. The goal is neither to deny disability nor to overidentify it, but to test plausible explanations with respectful, culturally responsive, multiple-source evidence.', ['language acquisition', 'cultural responsiveness', 'opportunity to learn']),
      section('Strengths-based, age-respectful planning', 'A useful learner profile describes observable strengths, emerging skills, interests, preferences, and support needs. Chronological-age respect remains essential even when instruction targets earlier-acquired or functional skills. Plan practice across people, materials, and natural routines so skills generalize, and fade prompts as independence grows. Avoid labels such as low functioning, which collapse a complex profile into a judgment and provide little information about what to teach next.', ['strengths-based planning', 'chronological-age respect', 'generalization']),
    ], [['What is the safest use of a developmental milestone?', 'As a broad reference point that prompts additional observation, not a stand-alone diagnosis.'], ['What is an ecological analysis?', 'A comparison of learner behavior across tasks, settings, supports, people, and consequences.'], ['Why gather home-language information?', 'To distinguish language access and acquisition from disability-related need.'], ['What makes a learner profile actionable?', 'Observable strengths, needs, contexts, supports, and current performance.'], ['How is generalization promoted?', 'Practice a skill across planned variations in people, materials, and natural settings.'], ['What does age-respectful instruction mean?', 'Match support to need while using materials and contexts appropriate to chronological age.']]),

  chapter('sp5355-ch-02', 'disability-characteristics-impact', 'Disability Characteristics and Educational Impact',
    'Connect common disability characteristics to possible educational effects while resisting stereotypes and basing every decision on the individual learner.',
    ['Recognize common patterns without diagnosing from a vignette.', 'Distinguish communication, executive-function, academic, and adaptive needs.', 'Select individualized instruction from current performance data.'], [
      section('Categories organize eligibility, not instruction', 'Disability categories can help teams communicate about eligibility and broad bodies of knowledge, but they do not prescribe a program. Two learners with the same category may differ in language, culture, health, cognition, sensory access, adaptive behavior, interests, and response to instruction. Begin with the IEP, present levels, evaluation evidence, and direct observation. The recurring exam rule is simple: common characteristics may inform a hypothesis, but individual evidence selects the support.', ['eligibility category', 'individualization', 'educational impact']),
      section('Academic and executive-function patterns', 'A specific learning disability may affect reading, written language, or mathematics unevenly and does not imply low overall intelligence. Dyslexia commonly involves word recognition, decoding, and spelling, while ADHD may affect initiation, inhibition, working memory, organization, and monitoring. Observe the precise task breakdown. Explicit instruction, external organization, feedback, and progress monitoring should target the demonstrated skill rather than a presumed deficit in effort or ability.', ['specific learning disability', 'dyslexia', 'executive function']),
      section('Communication, autism, and behavioral context', 'Communication differences affect how a learner receives information, expresses knowledge, or participates socially; they do not justify assumptions about comprehension. Autism profiles vary widely and may include differences in social communication, predictability, sensory processing, and restricted or focused interests. Emotional and behavioral performance is also contextual. Analyze interactions among learner skills, tasks, peers, expectations, and consequences rather than defining the child by one behavior.', ['communication access', 'autism', 'behavioral context']),
      section('Intellectual, adaptive, and co-occurring needs', 'Intellectual disability involves both intellectual functioning and adaptive behavior across conceptual, social, and practical domains. Adaptive performance should be understood in relevant cultural and community contexts. When disabilities co-occur, their effects may interact: a visual representation, motor response, or communication system that works for one need may fail when another is considered. Coordinated task analysis and trials are more reliable than stacking generic category-based supports.', ['intellectual functioning', 'adaptive behavior', 'co-occurring disabilities']),
    ], [['What does a disability category not determine?', 'A fixed instructional program or identical support package.'], ['What does dyslexia commonly affect?', 'Accurate or fluent word recognition, decoding, and spelling.'], ['Which functions may ADHD affect?', 'Initiation, inhibition, working memory, organization, planning, and self-monitoring.'], ['Why presume competence?', 'Expression or speech limitations do not establish limited understanding.'], ['What two areas are central to intellectual disability?', 'Intellectual functioning and adaptive behavior.'], ['How should co-occurring needs be planned for?', 'Analyze their combined effect on authentic tasks with coordinated specialist input.']]),

  chapter('sp5355-ch-03', 'adaptive-sensory-health-supports', 'Adaptive, Sensory, Physical, and Health Supports',
    'Design safe, dignified access for sensory, physical, health, adaptive, and assistive-technology needs while preserving active learner participation.',
    ['Match representation and response modes to assessed access needs.', 'Follow individualized health and safety plans within professional roles.', 'Evaluate assistive technology and placement through individualized data.'], [
      section('Equivalent access to information', 'Access for visual, hearing, or communication needs preserves the instructional concept while changing how information is perceived or exchanged. Examples include tactile graphics, usable enlargement, meaningful image descriptions, captioning, sign-language access, assistive listening technology, identified speakers, and AAC. The correct option is rarely simply more time with inaccessible material. Use the learner assessed media and communication needs, and verify that the support works in the actual classroom task.', ['accessible representation', 'communication mode', 'equivalent access']),
      section('Physical participation and positioning', 'Physical access includes reach, posture, fatigue, navigation, manipulation, and safe participation. Collaborate with the learner and relevant occupational therapy, physical therapy, nursing, and orientation or mobility professionals. Do not improvise transfers, positioning, feeding, or equipment procedures beyond training and the established plan. The goal is not passive observation: arrange materials, tools, roles, and response modes so the learner makes meaningful academic and functional decisions.', ['positioning', 'active participation', 'related services']),
      section('Health plans and school safety', 'Students with seizures, diabetes, allergies, respiratory conditions, or other health needs may have individualized emergency or health-care plans. Staff must know their assigned role, recognize relevant signs, protect immediate safety, and follow authorized medication, delegation, notification, and emergency procedures. Never invent treatment, give unauthorized food or medication, or wait unnecessarily for a family member when the plan calls for action. Legal and local nursing requirements govern practice.', ['health-care plan', 'emergency procedure', 'delegation']),
      section('Adaptive skills, AT trials, and placement', 'Adaptive instruction targets meaningful conceptual, social, and practical routines with observable criteria and age-respectful materials. Assistive technology decisions should be task based: define the barrier, trial a tool, teach its use, collect performance and usability data, and plan maintenance. Placement is likewise individualized. A continuum must be available, but a disability category never automatically selects a setting; the IEP and LRE analysis guide the decision.', ['adaptive skill', 'assistive technology trial', 'continuum of placements']),
    ], [['What is equivalent access?', 'A format or response mode that preserves the concept while removing an irrelevant barrier.'], ['What should guide communication access?', 'The learner communication mode, language needs, environment, technology, and direct-access opportunities.'], ['Who guides specialized positioning?', 'The student plan and appropriately trained school and related-service personnel.'], ['What should staff do during a health event?', 'Follow the individualized plan and trained emergency procedures.'], ['What is an AT trial?', 'A structured comparison of task performance, access, and usability with a candidate tool.'], ['What determines placement?', 'The individual IEP and LRE analysis, not diagnosis or administrative convenience.']]),

  chapter('sp5355-ch-04', 'individualized-planning-transition', 'Individualized Planning, IEPs, LRE, and Transition',
    'Build coherent programs from present levels through measurable goals, aligned services, progress reporting, access supports, placement, and transition outcomes.',
    ['Connect present levels, goals, services, and progress measures.', 'Distinguish accommodations from modifications.', 'Apply federal IEP, LRE, and transition baselines with state-law caution.'], [
      section('From present levels to measurable goals', 'Present levels describe current academic achievement and functional performance, the effect of disability on involvement and progress, and a baseline that supports goal design. A measurable goal names the condition, observable behavior, criterion, and when useful consistency or timeframe. Avoid vague verbs such as improve, understand, or try. The IEP must also describe how progress will be measured and when periodic reports will be provided, making the goal part of an ongoing decision cycle rather than an annual promise.', ['present levels', 'measurable annual goal', 'progress reporting']),
      section('A coherent individualized program', 'IEP sections should tell one connected story. Evaluation and present levels identify needs; goals define intended growth; specially designed instruction, related services, supplementary aids, program modifications, and supports for personnel address those goals; progress measures test effectiveness. The team considers the learner strengths, parent concerns, evaluation results, academic and functional needs, behavior, language, communication, Braille, and assistive technology as applicable.', ['specially designed instruction', 'supplementary aids', 'special factors']),
      section('Accommodation, modification, and LRE', 'An accommodation changes access, timing, setting, presentation, scheduling, or response while preserving the intended construct or standard. A modification changes the content, complexity, or expected performance. Neither automatically determines placement. Under LRE requirements, education with nondisabled peers is the starting consideration, supported by supplementary aids and services. Removal occurs only when education there cannot be achieved satisfactorily, and decisions cannot rest on category, convenience, or a preset program.', ['accommodation', 'modification', 'least restrictive environment']),
      section('Transition and IFSP foundations', 'Under the federal IDEA baseline, transition content begins no later than the first IEP in effect when the student turns 16, or earlier when appropriate, and is updated annually. It includes measurable postsecondary goals based on age-appropriate transition assessment plus needed transition services and courses of study. States may require an earlier age. At a high level, an IFSP is family centered and addresses early-intervention outcomes in natural environments, while an IEP defines the school-age educational program.', ['postsecondary goal', 'transition assessment', 'IFSP']),
    ], [['What belongs in present levels?', 'Current measurable academic and functional performance and the disability effect on progress or participation.'], ['What makes an annual goal measurable?', 'A condition, observable behavior, criterion, and a defined way to measure progress.'], ['What is an accommodation?', 'A change in access or response that preserves the intended construct or target.'], ['What is a modification?', 'A change to content, complexity, or the expected performance standard.'], ['What guides LRE placement?', 'The individual IEP and whether education with nondisabled peers can succeed with supports.'], ['When does federal transition content begin?', 'No later than the first IEP in effect at age 16, or earlier if appropriate; check state rules.']]),

  chapter('sp5355-ch-05', 'explicit-instruction-curriculum-access', 'Explicit Instruction and Curriculum Access',
    'Use systematic modeling, guided practice, feedback, scaffolding, UDL, and evidence-based academic routines to develop accurate and independent performance.',
    ['Plan explicit instruction with frequent learner responses.', 'Use and fade scaffolds from performance data.', 'Match reading, mathematics, and metacognitive support to the observed error.'], [
      section('The explicit-instruction cycle', 'Explicit instruction identifies the target, connects it to prior learning, models both actions and thinking, guides practice through carefully sequenced examples, checks every learner response, and gives timely corrective feedback. Independent practice follows demonstrated readiness rather than the clock. Systematic instruction uses logical sequencing and cumulative review. The teacher remains responsive: explicit does not mean inflexible, scripted without attention, or endless adult prompting.', ['explicit instruction', 'guided practice', 'cumulative review']),
      section('Task analysis, scaffolding, and release', 'Task analysis breaks a complex routine into observable, teachable steps. Scaffolds such as models, checklists, organizers, worked examples, prompts, and visual cues support a step that the learner cannot yet perform independently. Prompting requires a fading plan; otherwise support may become a new barrier. Monitor accuracy and independence, simplify the scaffold gradually, and restore or revise it if performance deteriorates. Do not confuse a support with completing the task for the learner.', ['task analysis', 'scaffold', 'prompt fading']),
      section('UDL and responsive grouping', 'Universal Design for Learning begins with a clear goal, anticipates predictable barriers, and offers purposeful options for engagement, representation, and action or expression. Options must preserve the target and be usable, not merely decorative. Flexible groups are another responsive tool: form them from current skill evidence and the lesson purpose, deliver the needed intensity, and regroup when performance changes. Disability categories should not become permanent instructional tracks.', ['Universal Design for Learning', 'flexible grouping', 'learner agency']),
      section('Target the academic process', 'Effective reading instruction distinguishes decoding, fluency, vocabulary, and comprehension. Mathematics support connects concrete and visual representations to symbols, explicitly teaches problem structures, and analyzes error patterns. Metacognitive routines such as plan-do-check teach learners to monitor performance. Across subjects, feedback should name the goal, describe the observable response, explain the next strategy, and give the learner an immediate opportunity to apply the correction.', ['decoding', 'error analysis', 'metacognition']),
    ], [['What are the core phases of explicit instruction?', 'Clear explanation and modeling, guided practice with feedback, then monitored independent practice.'], ['Why use task analysis?', 'To identify teachable steps and measure which parts of a complex routine are independent.'], ['When should a scaffold be faded?', 'When repeated evidence shows the learner can maintain the supported step with less help.'], ['What makes a UDL option purposeful?', 'It reduces a predictable barrier while preserving the clear learning goal.'], ['What does error analysis reveal?', 'The misconception or process step that should become the target of instruction.'], ['What is a metacognitive routine?', 'A taught process for planning, monitoring, and evaluating one own learning or performance.']]),

  chapter('sp5355-ch-06', 'behavior-environments-engagement', 'Behavior, Engagement, and Productive Environments',
    'Prevent difficulty through taught routines and accessible instruction, analyze behavioral function, teach replacement skills, and evaluate intervention fidelity and outcomes.',
    ['Build predictable, explicitly taught learning environments.', 'Connect FBA hypotheses to function-based BIPs.', 'Use engagement, regulation, safety, and fidelity data to revise support.'], [
      section('Prevention is instruction', 'Productive environments use a small number of clear expectations, explicitly taught routines, visual schedules, predictable transitions, accessible tasks, and high rates of successful responding. Teachers model, practice, prompt, and acknowledge expected behavior rather than assuming learners infer it. Instructional choice can increase agency when every option meets the same goal. Prevention also means matching task difficulty and support, because repeated failure, ambiguity, long waits, and inaccessible directions can evoke avoidable behavior.', ['behavior expectation', 'visual schedule', 'instructional choice']),
      section('From ABC data to a functional hypothesis', 'Define behavior in observable terms, then record antecedents, the response itself, and consequences across instances and noninstances. Look for patterns rather than treating one event as proof. A functional hypothesis predicts the conditions under which behavior is likely and the outcome it produces, such as attention, escape, access, or sensory regulation. Function is not moral intent and an FBA is not a psychiatric diagnosis; it is a basis for designing and testing educational support.', ['ABC data', 'functional hypothesis', 'functional behavioral assessment']),
      section('Function-based intervention and replacement skills', 'A strong behavior intervention plan adjusts antecedents, explicitly teaches a replacement behavior that efficiently serves the same function, reinforces the replacement, and prevents problem behavior from remaining the easiest route to the outcome. For escape from confusing work, a help request may be appropriate; for attention, teach an acceptable request and schedule attention. Measure both reduction and the growth of the replacement skill, participation, and quality of life.', ['behavior intervention plan', 'replacement behavior', 'reinforcement']),
      section('Regulation, safety, and fidelity', 'During escalation, follow the individualized safety plan, use calm and concise communication, reduce unnecessary demands or stimulation, allow regulated space, and avoid power struggles. Emergency procedures must comply with law, policy, training, and ethical limits. When a plan appears ineffective, examine implementation fidelity before rejecting the hypothesis. Outcome and fidelity data together show whether to coach implementation, adjust intensity, revisit function, or redesign the plan.', ['de-escalation', 'safety plan', 'implementation fidelity']),
    ], [['How are routines established?', 'Teach, model, practice, prompt, and reinforce them consistently in the setting where they occur.'], ['What does ABC stand for?', 'Antecedent, observable behavior, and consequence.'], ['What is a functional hypothesis?', 'A testable prediction about conditions and outcomes that maintain behavior.'], ['What makes a replacement behavior useful?', 'It is teachable, efficient, appropriate, and serves the same function.'], ['Why provide frequent opportunities to respond?', 'They increase active practice, engagement, and immediate instructional information.'], ['Why collect fidelity data?', 'To know whether an intervention was implemented well enough for outcome data to evaluate it.']]),

  chapter('sp5355-ch-07', 'assessment-quality-selection', 'Assessment Purpose, Quality, and Access',
    'Choose and interpret assessment evidence according to purpose, validity, reliability, culture, language, communication, and the construct actually being measured.',
    ['Distinguish validity, reliability, criterion, and norm interpretations.', 'Match formal and informal measures to decisions.', 'Remove construct-irrelevant access barriers without supplying answers.'], [
      section('Start with the decision and construct', 'Assessment selection begins with the question: screening, diagnosis, eligibility, instructional planning, progress monitoring, or outcome evaluation. Define the construct and choose evidence that represents it. Validity concerns whether evidence supports the intended interpretation and use; it is not a permanent stamp on a test. A measure of decoding cannot by itself justify a conclusion about comprehension, and an assessment useful for screening may not support a high-stakes eligibility decision.', ['assessment purpose', 'construct', 'validity']),
      section('Reliability and multiple sources', 'Reliability describes consistency across occasions, forms, items, or raters as relevant. Inconsistent scores weaken confidence in change, but a reliable measure can still be invalid for a particular purpose. IDEA requires a variety of tools and strategies and forbids one measure as the sole criterion. Combine tests, curriculum data, observation, interviews, work samples, intervention response, and family information to examine converging and competing explanations.', ['reliability', 'measurement error', 'multiple measures']),
      section('Cultural, linguistic, sensory, and communication access', 'Evaluation materials must be selected and administered to avoid racial or cultural discrimination and, unless clearly infeasible, use the learner native language or other communication mode in the form most likely to produce accurate information. Sensory, motor, and speech limitations should not distort results unless they are the target. An accommodation removes a construct-irrelevant barrier; a support that reveals the answer changes the construct and invalidates the interpretation.', ['nondiscriminatory assessment', 'native language', 'construct-irrelevant barrier']),
      section('Interpretation and observation', 'Criterion-referenced interpretations compare performance with defined skills or standards; norm-referenced interpretations compare relative standing with a norm group. Neither automatically determines eligibility. Informal assessment can be rigorous when purpose, administration, scoring, and decision rules are clear. Behavioral observation requires an operational definition that different observers can use consistently, plus representative contexts and attention to both occurrences and nonoccurrences.', ['criterion referenced', 'norm referenced', 'operational definition']),
    ], [['What is validity?', 'Evidence supporting the interpretation and use of assessment results for a defined purpose.'], ['What is reliability?', 'The consistency or dependability of measurement across relevant sources of variation.'], ['Why use multiple measures?', 'To avoid a single criterion and examine converging functional, developmental, academic, and contextual evidence.'], ['What is a construct-irrelevant barrier?', 'A response or access demand that affects the score but is not the skill intended to be measured.'], ['What is criterion-referenced interpretation?', 'Performance compared with specified skills, standards, or criteria.'], ['What makes a behavior definition operational?', 'It is observable, measurable, bounded, and usable consistently by different observers.']]),

  chapter('sp5355-ch-08', 'evaluation-eligibility-intervention', 'Evaluation, Eligibility, and Intervention',
    'Use timely, comprehensive, nondiscriminatory evaluation and intervention evidence to support team decisions without delaying evaluation or mistaking difference for disability.',
    ['Apply multiple-source, all-areas evaluation requirements.', 'Use intervention data without making RTI a gatekeeper.', 'Integrate exclusionary factors, family evidence, and team judgment.'], [
      section('Prereferral support and timely evaluation', 'General education intervention should define the concern, use an evidence-based support at adequate intensity, monitor response with a sensitive measure, and document fidelity. These actions can improve instruction and contribute valuable evaluation evidence. They cannot become an indefinite gate that delays or denies an evaluation when disability is suspected. Schools must follow applicable referral, notice, consent, and timeline procedures while continuing appropriate support.', ['prereferral', 'multi-tiered support', 'timely evaluation']),
      section('Comprehensive evaluation in all suspected areas', 'A comprehensive evaluation gathers relevant functional, developmental, and academic information and assesses all areas related to suspected disability, which may include health, vision, hearing, social-emotional status, cognition, academics, communication, and motor ability. It must identify educational needs whether or not they are commonly linked to the eventual category. Parent information, history, observation, and response data join technically sound formal measures in this process.', ['comprehensive evaluation', 'suspected disability', 'parent information']),
      section('Eligibility is a team synthesis', 'A group of qualified professionals and the parent reviews multiple sources, applicable criteria, educational impact, and the need for special education. No score, algorithm, diagnosis, or individual assigns eligibility automatically. For SLD and other decisions, teams consider whether inadequate instruction, limited English proficiency, cultural or economic factors, sensory needs, or another condition better explains the pattern. Exclusionary analysis protects accuracy; it is not a reason to ignore a real disability.', ['eligibility team', 'exclusionary factor', 'educational need']),
      section('FBA and intervention evidence', 'Functional behavioral assessment uses direct and indirect evidence to identify a testable relationship among context, behavior, and outcomes. Response-to-intervention data show how performance changed under defined instruction, not whether a student tried hard enough. Both types of evidence depend on implementation fidelity. The team integrates them with the full evaluation rather than treating either as a single test, a diagnosis, or an automatic eligibility formula.', ['response to intervention', 'functional behavioral assessment', 'fidelity']),
    ], [['What makes prereferral intervention informative?', 'A defined concern, evidence-based support, adequate intensity, repeated outcome data, and fidelity evidence.'], ['Can RTI delay an evaluation?', 'No. Intervention procedures may not be used to delay or deny a timely evaluation when disability is suspected.'], ['What areas must evaluation cover?', 'All areas related to the suspected disability and the learner educational needs.'], ['How is parent information used?', 'As a required and relevant source integrated with other evaluation evidence.'], ['Who determines eligibility?', 'Qualified professionals and the parent through an individualized review of multiple sources.'], ['What is the purpose of an FBA?', 'To develop a testable functional hypothesis that guides intervention design and evaluation.']]),

  chapter('sp5355-ch-09', 'progress-monitoring-data-decisions', 'Progress Monitoring and Data-Based Decisions',
    'Graph comparable repeated measures, interpret trend against goals, analyze errors and fidelity, and use prespecified decision rules to adjust instruction.',
    ['Design sensitive progress measures and goal trajectories.', 'Separate level, trend, variability, error pattern, and fidelity.', 'Communicate data clearly and apply timely decision rules.'], [
      section('Comparable repeated measurement', 'Progress monitoring uses brief, repeatable indicators aligned with the target skill. Administration and scoring conditions must be comparable enough that changes are interpretable. Establish a baseline, a measurable goal, and a monitoring schedule sensitive to the intervention intensity and decision window. Intensive intervention generally needs more frequent evidence than annual review, but testing every day with unrelated tasks creates noise rather than useful information.', ['progress monitoring', 'baseline', 'comparable measure']),
      section('Level, trend, goal line, and variability', 'Level describes the magnitude of performance; trend describes the direction and rate of change; variability describes scatter around that pattern. A goal line represents the expected trajectory from baseline to the desired outcome. Compare several points and the trend with that line rather than overreacting to one high or low observation. Flat or inadequate growth prompts review of fidelity, instruction, access, and goal appropriateness before a defensible adjustment.', ['level', 'trend', 'goal line']),
      section('Error analysis and fidelity', 'A total score may hide whether a learner misunderstands the concept, uses an inefficient strategy, makes a consistent procedural error, or loses accuracy only under a particular condition. Classify errors and examine correct responses to locate the instructional target. Collect implementation fidelity at the same time: dosage, adherence to components, quality, and learner opportunity. Outcomes cannot fairly evaluate a plan that was not delivered as designed.', ['error analysis', 'implementation fidelity', 'instructional target']),
      section('Decision rules and stakeholder communication', 'A decision rule states in advance what pattern will trigger continuation, intensification, adaptation, or review. Requiring several comparable points and adequate fidelity limits reaction to measurement error while avoiding months of ineffective instruction. Communicate graphs in plain language: label the skill, units, dates, baseline, goal, intervention changes, and trend. Explain uncertainty, invite family and learner observations, and record the decision and next review date.', ['decision rule', 'data visualization', 'stakeholder communication']),
    ], [['What is a progress-monitoring measure?', 'A repeatable, sensitive indicator aligned with the target skill and decision.'], ['What does a goal line show?', 'The expected rate of improvement from baseline to the desired outcome.'], ['Why not react to one data point?', 'A single score may reflect ordinary variability or measurement error rather than a stable change.'], ['What does error analysis add?', 'It identifies the misconception, strategy, or task step hidden by a total score.'], ['Why pair fidelity and outcome data?', 'To distinguish an ineffective plan from incomplete or inconsistent implementation.'], ['What makes a decision rule defensible?', 'It is prespecified and uses multiple comparable data points, trend, and fidelity.']]),

  chapter('sp5355-ch-10', 'law-ethics-equity', 'Law, Ethics, Safeguards, and Equity',
    'Apply foundational IDEA and Section 504 concepts, protect participation and confidentiality, recognize bias, and verify current jurisdiction-specific requirements.',
    ['Distinguish FAPE, Child Find, safeguards, IDEA, and Section 504.', 'Protect records and use ethical evidence standards.', 'Identify system bias without withholding individualized evaluation.'], [
      section('FAPE, Child Find, and individualized entitlement', 'IDEA makes FAPE available to eligible children through special education and related services provided at public expense under an appropriately developed and implemented IEP. It does not promise identical outcomes or a category-based package. Child Find is an affirmative duty to identify, locate, and evaluate children who may need special education, including those who advance from grade to grade. Passing grades, mobility, or extensive informal support do not automatically remove the duty.', ['FAPE', 'Child Find', 'individualized entitlement']),
      section('Participation and procedural safeguards', 'Procedural safeguards make educational participation meaningful. Prior written notice explains actions the agency proposes or refuses, why, the evidence considered, alternatives, and relevant protections. Parents have rights related to records, independent educational evaluation, mediation, due process, complaints, consent, and notice subject to governing rules. On exam scenarios, look for timely information, documented rationale, access to participation, and avoidance of unilateral decisions.', ['prior written notice', 'parent participation', 'procedural safeguard']),
      section('IDEA, Section 504, and confidentiality', 'IDEA is an education statute with eligibility categories, special education, related services, IEP procedures, and FAPE requirements. Section 504 is a civil-rights law prohibiting disability discrimination in recipients of federal financial assistance and may require accommodations, related aids, or services for equal access even when IDEA eligibility is not met. Protect personally identifiable education information, use secure channels, and share only with authorized people who have a legitimate role.', ['Individuals with Disabilities Education Act', 'Section 504', 'confidentiality']),
      section('Equity, evidence, and legal caution', 'Cultural and linguistic bias can enter referral definitions, discipline, opportunity to learn, assessment, interpretation, and placement. Audit systems and gather culturally responsive evidence without assuming group differences prove disability or using disproportionality to deny an individual evaluation. Ethical practice uses credible evidence, current standards, student data, informed team review, and the least harmful effective approach. Federal baselines do not replace current state law, local policy, or legal advice.', ['disproportionality', 'cultural bias', 'evidence-based practice']),
    ], [['What is FAPE?', 'An appropriate public special education program and related services for an eligible child, provided without charge under IDEA.'], ['What is Child Find?', 'The duty to identify, locate, and evaluate children who may need special education.'], ['What does prior written notice explain?', 'A proposed or refused action, reasons, evidence, alternatives, and applicable safeguards.'], ['How does Section 504 differ at a high level?', 'It is a civil-rights protection against disability discrimination and can require equal-access supports.'], ['Who may receive identifiable education information?', 'Authorized people with a legitimate educational role, through protected channels.'], ['How should disproportionality be addressed?', 'Audit systems and bias while preserving individualized, culturally responsive evaluation and support.']]),

  chapter('sp5355-ch-11', 'collaboration-families-teams', 'Collaboration with Families and School Teams',
    'Share ownership across educators, paraprofessionals, families, specialists, and students through defined roles, reciprocal communication, common data, and follow-up.',
    ['Use genuine co-planning and co-teaching roles.', 'Supervise paraprofessionals and coordinate related services.', 'Support family and student voice in data-based team decisions.'], [
      section('Co-teaching is shared ownership', 'Effective co-teachers jointly plan goals, access, grouping, roles, checks for understanding, behavior supports, and follow-up. Both teach and assess all learners; the special educator is not an assistant assigned permanently to the back table, and the general educator does not own all content alone. Select among co-teaching structures because they fit the lesson and learner data, then examine whether both educators expertise and all students participation are actually being used.', ['co-planning', 'co-teaching', 'shared ownership']),
      section('Paraprofessional direction and learner independence', 'Teachers retain responsibility for instructional decisions, assessment, and supervision. Paraprofessionals need a clear purpose, authorized information, models of the support, boundaries, data procedures, and timely feedback. Plans should specify when and how prompts fade so close adult proximity does not isolate the learner or create dependence. Paraprofessionals should not be expected to invent specialized instruction, write the IEP, or make independent placement and grading decisions.', ['paraprofessional supervision', 'prompt dependence', 'role boundary']),
      section('Families, students, and reciprocal expertise', 'Families contribute knowledge of history, culture, priorities, routines, strengths, and performance outside school. Listen for the concern behind disagreement, review evidence together, use accessible language and interpretation, and identify what additional data could resolve uncertainty. Students can describe strengths, preferences, goals, and helpful supports when the process and communication format are accessible. Participation is not merely attendance; it means information can influence the decision.', ['family partnership', 'student voice', 'self-determination']),
      section('Related services and productive disagreement', 'Occupational therapy, physical therapy, speech-language, school psychology, counseling, nursing, behavior, and other specialists contribute distinct expertise toward educational access. Integrate recommendations into authentic routines, define who does what, and exchange fidelity and outcome data. When colleagues disagree, operationalize the concern, inspect common evidence, test one feasible adjustment, and schedule review. Seniority and confidence are not substitutes for a shared question and data.', ['related service', 'interprofessional collaboration', 'shared data']),
    ], [['What is shared ownership in co-teaching?', 'Both educators plan, teach, assess, and support all learners using complementary expertise.'], ['Who retains instructional responsibility when a paraprofessional supports a student?', 'The responsible licensed educator and school team.'], ['How are paraprofessional prompts prevented from becoming dependence?', 'Define the purpose, teach the procedure, monitor performance, and plan systematic fading.'], ['What makes family collaboration reciprocal?', 'Family evidence and priorities are invited, understood, and allowed to shape team decisions.'], ['How can a student prepare for an IEP meeting?', 'Practice describing strengths, needs, preferences, goals, and useful supports in an accessible format.'], ['What turns team disagreement into learning?', 'A shared operational definition, common data, a testable adjustment, and a review date.']]),

  chapter('sp5355-ch-12', 'professional-learning-advocacy', 'Professional Learning, Advocacy, and Boundaries',
    'Improve practice through outcome-linked reflection, targeted learning, ethical advocacy, safety and reporting duties, transition coordination, and current-rule verification.',
    ['Link professional reflection and development to learner evidence.', 'Advocate through documented, confidential, role-appropriate channels.', 'Apply reporting, consent, and jurisdiction-specific professional boundaries.'], [
      section('Reflection tied to learner outcomes', 'Useful reflection asks which learners met the target, what response and error patterns occurred, which supports were delivered, how fidelity varied, and what change should be tested next. Coverage and student enjoyment may matter, but they do not establish learning. Keep the unit of analysis specific enough to act on. When an adjustment produces better evidence, retain and generalize it; when it fails despite adequate implementation, revise the hypothesis rather than blaming learners.', ['reflective practice', 'student outcome', 'instructional hypothesis']),
      section('Professional learning that transfers', 'Choose development from an identified practice need, credible evidence, and the learners you serve. Strong learning includes modeling, rehearsal, feedback, coaching, classroom application, and follow-up rather than attendance alone. Measure both implementation and student effects. Collaborate across disciplines and seek supervision when a practice exceeds current competence. Social-media popularity, testimonials, or a certificate cannot substitute for evidence, ethical review, and demonstrated safe use.', ['professional development', 'coaching', 'implementation evidence']),
      section('Advocacy, safety, and role boundaries', 'Advocacy documents the educational barrier and impact, identifies applicable requirements, proposes feasible solutions, uses team and administrative channels, and follows up. Protect confidentiality and do not promise authority or resources you do not have. For suspected abuse, neglect, or immediate harm, follow mandatory reporting and school safety procedures promptly; do not promise secrecy, conduct an unauthorized investigation, or circulate details beyond authorized personnel.', ['advocacy', 'mandatory reporting', 'professional boundary']),
      section('Transition coordination and current requirements', 'Outside agencies can strengthen transition planning, but invitations and information sharing must follow required parent or adult-student consent. The public agency does not escape its responsibilities when another agency participates or fails to deliver. Professional practice checks current federal regulations, state law, licensure standards, district policy, and authoritative guidance because timelines and procedures can change or add protections. Study summaries support preparation, not legal advice.', ['agency coordination', 'consent', 'jurisdiction-specific requirement']),
    ], [['What makes reflection actionable?', 'It connects educator actions, fidelity, learner response patterns, and one specific next change.'], ['How is professional development selected?', 'From an identified practice need, credible evidence, and relevance to current learners.'], ['How is professional learning evaluated?', 'Through implementation evidence and effects on meaningful learner outcomes.'], ['What is ethical advocacy?', 'Documented, confidential, role-appropriate action through established channels to remove an educational barrier.'], ['What should an educator do with a reportable safety concern?', 'Follow required reporting and safety procedures promptly without promising secrecy.'], ['Why verify state and local rules?', 'They may add timelines or protections to federal baselines and can change over time.']]),
];

const memoryAids = [
  { title: 'Milestones: Notice, Do Not Diagnose', content: 'Use milestones to notice a pattern and gather more information. One difference, one day, or one context is not a diagnosis. Think: observe across domains, settings, time, language, and opportunity.', tags: ['development', 'assessment'], references: [S.ETS] },
  { title: 'Context Before Character', content: 'When performance changes, compare task, environment, language, sensory load, supports, people, and consequences before attributing the result to motivation or a fixed trait.', tags: ['development', 'behavior'], references: [S.ETS] },
  { title: 'Category Is Not Curriculum', content: 'A disability category organizes eligibility; current strengths, needs, goals, access, response data, and the IEP determine instruction. Same label does not mean same program.', tags: ['individualization', 'disability'], references: [S.ETS] },
  { title: 'Access Preserves the Target', content: 'An accommodation removes an irrelevant barrier while preserving what is taught or measured. A modification changes the content, complexity, or expected performance.', tags: ['access', 'accommodation'], references: [S.IDEA_ASSESS] },
  { title: 'AT: Barrier, Trial, Teach, Track', content: 'Define the task barrier, trial a candidate tool in authentic routines, teach the learner and staff to use it, and track access, independence, usability, and outcomes.', tags: ['assistive technology', 'access'], references: [S.IDEA_IEP_REVIEW] },
  { title: 'IEP Coherence Chain', content: 'Evaluation evidence leads to present levels; present levels lead to measurable goals; goals align with services and supports; progress measures test whether the program works.', tags: ['IEP', 'planning'], references: [S.IDEA_IEP] },
  { title: 'Measurable Goal: C-B-C', content: 'Remember Condition, observable Behavior, and Criterion. Add consistency, timeframe, and measurement method when needed so different team members can determine progress.', tags: ['goals', 'progress monitoring'], references: [S.IDEA_IEP] },
  { title: 'LRE Is an Analysis, Not a Place', content: 'Start with the individual IEP and education with nondisabled peers using supplementary aids and services. Category, convenience, and a preset program do not decide placement.', tags: ['LRE', 'placement'], references: [S.IDEA_LRE, S.IDEA_PLACEMENT] },
  { title: 'Transition: Assess, Aim, Act', content: 'Use age-appropriate transition assessment, write measurable postsecondary aims, and define services and courses of study that help the student act toward those outcomes.', tags: ['transition', 'IEP'], references: [S.IDEA_IEP] },
  { title: 'Explicit Instruction: I Do, We Do, You Do - With Data', content: 'Explain and model the strategy, guide many responses with feedback, then release independent practice when evidence shows readiness. Return to guidance when error patterns require it.', tags: ['instruction', 'scaffolding'], references: [S.ETS] },
  { title: 'UDL: Goal, Barrier, Option', content: 'Clarify the learning goal, anticipate the barrier, and select purposeful options for engagement, representation, or action and expression that preserve the goal.', tags: ['UDL', 'access'], references: [S.ETS] },
  { title: 'ABC to Function', content: 'Define the observable behavior, then compare antecedents and consequences across occurrences and nonoccurrences. Build a testable functional hypothesis, not a judgment about intent.', tags: ['FBA', 'behavior'], references: [S.IES_BEHAVIOR] },
  { title: 'Function-Based BIP: Prevent, Teach, Reinforce', content: 'Prevent predictable triggers, teach an efficient appropriate response serving the same function, and reinforce that response while collecting outcome and fidelity data.', tags: ['BIP', 'replacement behavior'], references: [S.IES_BEHAVIOR] },
  { title: 'Assessment: Purpose Before Product', content: 'Name the decision and construct first. Then choose valid, reliable, accessible, culturally and linguistically appropriate sources that can actually support that interpretation.', tags: ['assessment', 'validity'], references: [S.IDEA_EVAL] },
  { title: 'No Single Measure', content: 'Eligibility and programming integrate tests, observation, work, intervention response, history, family information, and context. One score never becomes the sole criterion.', tags: ['evaluation', 'eligibility'], references: [S.IDEA_EVAL] },
  { title: 'Progress Graph: Level, Trend, Goal, Fidelity', content: 'Read current level, rate of change, distance from the goal line, and variability. Before changing the intervention theory, verify that the plan was implemented adequately.', tags: ['progress monitoring', 'data'], references: [S.IES_DATA] },
  { title: 'IDEA and 504 Quick Contrast', content: 'IDEA provides special education through eligibility and IEP procedures; Section 504 is a civil-rights protection against disability discrimination and may require equal-access supports.', tags: ['IDEA', 'Section 504'], references: [S.SECTION_504] },
  { title: 'Collaboration: Define, Do, Data, Discuss', content: 'Define the goal and roles, implement the agreed action, collect shared outcome and fidelity data, then discuss what to retain or revise at a scheduled follow-up.', tags: ['collaboration', 'teams'], references: [S.ETS] },
  { title: 'Para Support: Direct, Model, Observe, Fade', content: 'The teacher directs the purpose and boundary, models the procedure, observes and gives feedback, and plans prompt fading so support develops learner independence.', tags: ['paraprofessional', 'supervision'], references: [S.ETS] },
  { title: 'Federal Floor, Current Local Rules', content: 'Federal requirements establish a baseline. State law and local policy may add protections or earlier timelines, so verify current authoritative rules and seek legal guidance when needed.', tags: ['law', 'professional practice'], references: [S.ETS, S.IDEA_IEP] },
];

module.exports = { chapters, memoryAids };
